          withPattern: `import java.util.ArrayList;
import java.util.List;

// Observer interface
interface Observer {
    void update(String announcement);
}

// Subject interface
interface Subject {
    void subscribe(Observer o);
    void unsubscribe(Observer o);
    void notifyObservers(String message);
}

// Concrete Subject — the Principal
class Principal implements Subject {
    private List<Observer> observers = new ArrayList<>();
    private String name;

    public Principal(String name) { this.name = name; }

    @Override
    public void subscribe(Observer o)   { observers.add(o); }

    @Override
    public void unsubscribe(Observer o) { observers.remove(o); }

    @Override
    public void notifyObservers(String message) {
        System.out.println("[" + name + " announces]: " + message);
        for (Observer o : observers) {
            o.update(message);
        }
    }

    public void makeAnnouncement(String msg) {
        notifyObservers(msg);
    }
}

// Concrete Observers
class Teacher implements Observer {
    private String name;
    public Teacher(String name) { this.name = name; }

    @Override
    public void update(String announcement) {
        System.out.println("  Teacher " + name
            + " → Preparing response to: " + announcement);
    }
}

class Student implements Observer {
    private String name;
    public Student(String name) { this.name = name; }

    @Override
    public void update(String announcement) {
        System.out.println("  Student " + name
            + " → Noted: " + announcement);
    }
}

public class Main {
    public static void main(String[] args) {
        Principal principal = new Principal("Dr. Ahmed");

        Observer t1 = new Teacher("Mr. Karim");
        Observer t2 = new Teacher("Ms. Rina");
        Observer s1 = new Student("Afif");
        Observer s2 = new Student("Sadia");

        principal.subscribe(t1);
        principal.subscribe(t2);
        principal.subscribe(s1);
        principal.subscribe(s2);

        principal.makeAnnouncement("School closed tomorrow for weather.");

        System.out.println();
        principal.unsubscribe(s2); // Sadia left school
        principal.makeAnnouncement("Annual sports day is Friday.");
    }
}`,
